/*##############################################################
 * 그리드, 트리뷰, 데이터리스트 이벤트
 *##############################################################*/
 /**
 * 그리드 셀 클릭 이벤트
 */
scwin.grdFileList_oncellclick = function (rowIndex, columnIndex, columnId) {
    if(columnId == "fileName"){
        $c.gus.cfGetFileURL(ds_fileList.getCellData(rowIndex, "fileName"), ds_fileList.getCellData(rowIndex, "filePath"));
	}
};
